+    // Cleanup
+    for (entries) |entry| {
+        std.testing.allocator.free(entry.name);
+    }
+    std.testing.allocator.free(entries);
+
+    // Remove directory recursively
+    _ = try registry.call("filesystem", "remove-dir", &[_]Value{
+        Value{ .string = test_dir },
+        Value{ .bool = true },
+    });
+}
